INSERT INTO ui_translations (lang, key, value) VALUES
  ('en', 'doc_welcome_title', 'Welcome to Aliolo'),
  ('en', 'doc_welcome_desc', 'Aliolo is a visual learning platform designed to help you master subjects through flashcards and interactive testing.'),
  ('en', 'doc_pillars_title', 'The 8 Core Pillars'),
  ('en', 'doc_pillars_desc', 'All content in Aliolo is organized into 8 foundational pillars: Academic & Professional, World, Nature, Health, Humanities, Leisure, Engineering, and Other. These categories provide a structured framework for all subjects across the platform.'),
  ('en', 'doc_leaderboard_title', 'Global Leaderboard'),
  ('en', 'doc_leaderboard_desc', 'Compete with learners worldwide! Earn XP by completing card sessions and climb the ranks. Your position is updated in real-time as you master new subjects.'),
  ('en', 'doc_friends_title', 'Friends & Invitations'),
  ('en', 'doc_friends_desc', 'Learning is better together! Invite friends to Aliolo through your profile. You can track each other''s progress and stay motivated by seeing who maintains the longest streak.'),
  ('en', 'doc_streaks_title', 'Streak System'),
  ('en', 'doc_streaks_desc', 'Consistency is key! Complete your daily goal every day to build your streak. Don''t miss a day, or the streak will reset.'),
  ('en', 'doc_goals_title', 'Daily Goals'),
  ('en', 'doc_goals_desc', 'Set your daily card completion target in the settings. Changes to your goal take effect starting the next day.'),
  ('en', 'doc_public_title', 'Public vs Private'),
  ('en', 'doc_public_desc', 'Subjects can be private (visible only to you) or public. Public content is shared with the entire Aliolo community, allowing everyone to discover and learn from your creations.'),
  ('en', 'doc_sync_title', 'Cloud Sync'),
  ('en', 'doc_sync_desc', 'Your progress is automatically synced to the cloud. You can switch between web and desktop versions without losing your streak.'),
  ('en', 'doc_feedback_title', 'Feedback System'),
  ('en', 'doc_feedback_desc', 'Help us improve! Use the feedback icon (Icons.feedback) on any Subject or Folder to report issues. You can also send general app feedback through the Support section.'),
  ('en', 'doc_lang_title', 'Learning Language'),
  ('en', 'doc_lang_desc', 'Always select your preferred learning language in the top menu before selecting a subject. This ensures the correct audio and translations are loaded.'),
  ('en', 'doc_filters_title', 'Search & Filters'),
  ('en', 'doc_filters_desc', 'Quickly find content using the search bar. You can filter by Age Group (Early to Advanced) or narrow your view to specific Collections and Folders.'),
  ('en', 'doc_flashcards_title', 'Visual Flashcards'),
  ('en', 'doc_flashcards_desc', 'Each subject contains a set of cards. While images and audio are supported, they are optional—content can be purely textual or dynamically generated.'),
  ('en', 'doc_study_modes_title', 'Adaptive Study Modes'),
  ('en', 'doc_study_modes_desc', 'Aliolo supports various testing modes based on your content: Image-to-Text, Audio-to-Image, and Text-to-Audio. This multi-sensory approach ensures you master subjects from every angle.'),
  ('en', 'doc_testing_title', 'Interactive Testing'),
  ('en', 'doc_testing_desc', 'Challenge yourself with multiple-choice questions (MCQ). The app will automatically advance as you answer, helping you learn faster.'),
  ('en', 'doc_autoplay_title', 'Auto-Play Learning'),
  ('en', 'doc_autoplay_desc', 'The app can automatically advance to the next card after you answer. Correct answers wait 1s, while incorrect ones wait 2s to let you review.'),
  ('en', 'doc_math_title', 'Mathematical Subjects'),
  ('en', 'doc_math_desc', 'Mathematical subjects use specialized engines to generate card visualizations in real-time. These subjects feature unique learning and testing modes tailored to specific mathematical concepts, ensuring a more effective practice environment.'),
  ('en', 'doc_organization_title', 'Organizing Content'),
  ('en', 'doc_organization_desc', 'Use Folders to group related Subjects together. You can also create Collections to organize Subjects into curated paths.'),
  ('en', 'doc_creation_title', 'Creating Subjects & Cards'),
  ('en', 'doc_creation_desc', 'Create your own Subjects and add visual Flashcards. Each card supports an image and an optional audio file for pronunciation.'),
  ('en', 'doc_collections_purpose_title', 'The Purpose of Collections'),
  ('en', 'doc_collections_purpose_desc', 'Collections are curated paths that group Subjects together. When you start a session from a Collection, the system mixes cards from all included subjects to provide a randomized, comprehensive test.'),
  ('en', 'doc_card_scope_title', 'Where Cards Live'),
  ('en', 'doc_card_scope_desc', 'Cards are the building blocks of learning and always belong to a specific Subject. While you can organize Subjects into Folders or Collections, cards themselves must be created within a Subject.'),
  ('en', 'doc_localization_ui_title', 'Adding Translations'),
  ('en', 'doc_localization_ui_desc', 'To add localized data, simply tap the language code icon (e.g., EN, ES, FR) in the editor header. This allows you to provide specific names, descriptions, and card content for each supported language. The "Global" tab serves as the primary fallback if no specific translation is provided.'),
  ('en', 'doc_localization_details_title', 'How Localization Works'),
  ('en', 'doc_localization_details_desc', 'The "Global" language is your primary fallback—it can be any language you choose. If you provide specific translations (like English or Spanish), they will override the Global data only when a user selects that specific UI language.'),
  ('en', 'doc_json_title', 'JSON Localization'),
  ('en', 'doc_json_desc', 'Advanced creators can use JSON data to provide localized names and descriptions, making subjects accessible across all supported languages.'),
  ('en', 'doc_media_title', 'Media Upload Limits'),
  ('en', 'doc_media_desc', 'To ensure fast sync, keep images under 5MB and audio files under 10MB.')
INSERT INTO ui_translations (lang, key, value) VALUES
  ('id', 'doc_welcome_title', 'Selamat Datang di Aliolo'),
  ('id', 'doc_welcome_desc', 'Aliolo adalah platform pembelajaran visual yang dirancang untuk membantu Anda menguasai subjek melalui kartu flash dan pengujian interaktif.'),
  ('id', 'doc_pillars_title', '8 Pilar Utama'),
  ('id', 'doc_pillars_desc', 'Semua konten di Aliolo disusun menjadi 8 pilar dasar: Akademik & Profesional, Dunia, Alam, Tubuh Manusia, Humaniora, Waktu Luang, Teknik, dan Lainnya. Kategori-kategori ini menyediakan kerangka kerja terstruktur untuk semua subjek di seluruh platform.'),
  ('id', 'doc_leaderboard_title', 'Papan Peringkat Global'),
  ('id', 'doc_leaderboard_desc', 'Bersaing dengan pelajar di seluruh dunia! Dapatkan XP dengan menyelesaikan sesi kartu dan naik peringkat. Posisi Anda diperbarui secara real-time saat Anda menguasai subjek baru.'),
  ('id', 'doc_friends_title', 'Teman & Undangan'),
  ('id', 'doc_friends_desc', 'Belajar lebih baik bersama-sama! Undang teman ke Aliolo melalui profil Anda. Anda dapat melacak kemajuan satu sama lain dan tetap termotivasi dengan melihat siapa yang mempertahankan streak terlama.'),
  ('id', 'doc_streaks_title', 'Sistem Streak'),
  ('id', 'doc_streaks_desc', 'Konsistensi adalah kunci! Selesaikan target harian Anda setiap hari untuk membangun streak Anda. Jangan lewatkan satu hari pun, atau streak akan diatur ulang.'),
  ('id', 'doc_goals_title', 'Target Harian'),
  ('id', 'doc_goals_desc', 'Atur target penyelesaian kartu harian Anda di pengaturan. Perubahan pada target Anda mulai berlaku besok.'),
  ('id', 'doc_public_title', 'Publik vs Privat'),
  ('id', 'doc_public_desc', 'Subjek dapat bersifat privat (hanya terlihat oleh Anda) atau publik. Konten publik dibagikan kepada seluruh komunitas Aliolo, memungkinkan semua orang untuk menemukan dan belajar dari kreasi Anda.'),
  ('id', 'doc_sync_title', 'Sinkronisasi Cloud'),
  ('id', 'doc_sync_desc', 'Kemajuan Anda secara otomatis disinkronkan ke cloud. Anda dapat beralih antara versi web dan desktop tanpa kehilangan streak Anda.'),
  ('id', 'doc_feedback_title', 'Sistem Umpan Balik'),
  ('id', 'doc_feedback_desc', 'Bantu kami berkembang! Gunakan ikon umpan balik (Icons.feedback) pada Subjek atau Folder apa pun untuk melaporkan masalah. Anda juga dapat mengirim umpan balik aplikasi umum melalui bagian Dukungan.'),
  ('id', 'doc_lang_title', 'Bahasa Pembelajaran'),
  ('id', 'doc_lang_desc', 'Selalu pilih bahasa pembelajaran pilihan Anda di menu atas sebelum memilih subjek. Ini memastikan audio dan terjemahan yang benar dimuat.'),
  ('id', 'doc_filters_title', 'Pencarian & Filter'),
  ('id', 'doc_filters_desc', 'Temukan konten dengan cepat menggunakan bilah pencarian. Anda dapat memfilter berdasarkan Kelompok Usia (Dini hingga Lanjutan) atau mempersempit tampilan Anda ke Koleksi dan Folder tertentu.'),
  ('id', 'doc_flashcards_title', 'Kartu Flash Visual'),
  ('id', 'doc_flashcards_desc', 'Setiap subjek berisi sekumpulan kartu. Meskipun gambar dan audio didukung, keduanya bersifat opsional—konten dapat berupa teks murni atau dihasilkan secara dinamis.'),
  ('id', 'doc_study_modes_title', 'Mode Belajar Adaptif'),
  ('id', 'doc_study_modes_desc', 'Aliolo mendukung berbagai mode pengujian berdasarkan konten Anda: Gambar-ke-Teks, Audio-ke-Gambar, dan Teks-ke-Audio. Pendekatan multi-indrawi ini memastikan Anda menguasai subjek dari segala sudut.'),
  ('id', 'doc_testing_title', 'Pengujian Interaktif'),
  ('id', 'doc_testing_desc', 'Tantang diri Anda dengan pertanyaan pilihan ganda (MCQ). Aplikasi akan otomatis berlanjut saat Anda menjawab, membantu Anda belajar lebih cepat.'),
  ('id', 'doc_autoplay_title', 'Pembelajaran Putar Otomatis'),
  ('id', 'doc_autoplay_desc', 'Aplikasi dapat secara otomatis beralih ke kartu berikutnya setelah Anda menjawab. Jawaban yang benar menunggu 1 detik, sedangkan yang salah menunggu 2 detik untuk membiarkan Anda meninjau.'),
  ('id', 'doc_math_title', 'Subjek Matematika'),
  ('id', 'doc_math_desc', 'Subjek matematika menggunakan mesin khusus untuk menghasilkan visualisasi kartu secara real-time. Subjek-subjek ini memiliki mode pembelajaran dan pengujian unik yang disesuaikan dengan konsep matematika tertentu.'),
  ('id', 'doc_organization_title', 'Mengatur Konten'),
  ('id', 'doc_organization_desc', 'Gunakan Folder untuk mengelompokkan Subjek terkait. Anda juga dapat membuat Koleksi untuk menyusun Subjek ke dalam jalur yang dikurasi.'),
  ('id', 'doc_creation_title', 'Membuat Subjek & Kartu'),
  ('id', 'doc_creation_desc', 'Buat Subjek Anda sendiri dan tambahkan Kartu Flash visual. Setiap kartu mendukung gambar dan file audio opsional untuk pengucapan.'),
  ('id', 'doc_collections_purpose_title', 'Tujuan Koleksi'),
  ('id', 'doc_collections_purpose_desc', 'Koleksi adalah jalur kurasi yang mengelompokkan Subjek bersama-sama. Saat Anda memulai sesi dari Koleksi, sistem mencampur kartu dari semua subjek yang disertakan untuk memberikan tes acak yang komprehensif.'),
  ('id', 'doc_card_scope_title', 'Di Mana Kartu Berada'),
  ('id', 'doc_card_scope_desc', 'Kartu adalah blok bangunan pembelajaran dan selalu termasuk dalam Subjek tertentu. Meskipun Anda dapat mengatur Subjek ke dalam Folder atau Koleksi, kartu itu sendiri harus dibuat di dalam Subjek.'),
  ('id', 'doc_localization_ui_title', 'Menambahkan Terjemahan'),
  ('id', 'doc_localization_ui_desc', 'Untuk menambahkan data terlokalisasi, cukup ketuk ikon kode bahasa (misalnya, EN, ES, FR) di header editor. Tab "Global" berfungsi sebagai fallback utama jika tidak ada terjemahan khusus yang disediakan.'),
  ('id', 'doc_localization_details_title', 'Cara Kerja Lokalisasi'),
  ('id', 'doc_localization_details_desc', 'Bahasa "Global" adalah fallback utama Anda—bisa berupa bahasa apa pun yang Anda pilih. Jika Anda menyediakan terjemahan khusus, terjemahan tersebut akan menggantikan data Global hanya saat pengguna memilih bahasa UI tersebut.'),
  ('id', 'doc_json_title', 'Lokalisasi JSON'),
  ('id', 'doc_json_desc', 'Kreator tingkat lanjut dapat menggunakan data JSON untuk menyediakan nama dan deskripsi terlokalisasi, membuat subjek dapat diakses di semua bahasa yang didukung.'),
  ('id', 'doc_media_title', 'Batas Unggahan Media'),
  ('id', 'doc_media_desc', 'Untuk memastikan sinkronisasi cepat, simpan gambar di bawah 5MB dan file audio di bawah 10MB.')
