-- SQL Script to add documentation translations for all supported languages
-- Run this in your Supabase SQL Editor

-- English (en) - reference
ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;

-- Note: Translating the detailed documentation descriptions into all 34 languages 
